query:
SELECT id, name FROM trilhas ORDER BY id;

SELECT t.id as trilhaId, t.name as trilhaNome, COUNT(tc.competenciaId) as numComps
FROM trilhas t
LEFT JOIN trilha_competencias tc ON tc.trilhaId = t.id
GROUP BY t.id, t.name;

